#include <bits/stdc++.h>
using namespace std;

const int N=210,M=4e4+10;

int n,m;
int head[N],ver[M],nxt[M],tot;
int dfn[N],low[N],num,stk[N],top,c[N],cnt;
bool ins[N];

void add(int x,int y){
    ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
        }else if(ins[y])
            low[x]=min(low[x],dfn[y]);

    if(dfn[x]==low[x]){
        cnt++;
        int z=0;
        do{
            z=stk[top--],ins[z]=0;
            c[z]=cnt;
        }while(z!=x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int a,b,c;
        char op[5];
        scanf("%d%d%d",&a,&b,&c);
        a++,b++;
        scanf("%s",op);
        if(op[0]=='A'){
            if(c==0){
                add(a+n,b);
                add(b+n,a);
            }else{
                add(a,a+n);
                add(b,b+n);
            }
        }else if(op[0]=='O'){
            if(c==0){
                add(a+n,a);
                add(b+n,b);
            }else{
                add(a,b+n);
                add(b,a+n);
            }
        }else{
            add(a,b+c*n);
            add(b+c*n,a);
            add(a+n,b+n-c*n);
            add(b+n-c*n,a+n);
        }
    }

    for(int i=1;i<=2*n;i++)
        if(!dfn[i])
            tarjan(i);
    for(int i=1;i<=n;i++)
        if(c[i]==c[i+n]){
            printf("NO");
            return 0;
        }
    printf("YES");
    return 0;
}
